// ============================================================
// Mineral tables for adult horses
// Kilde: NRC 2007 minimumsnorm × 1.25
// PDF s. 206: «Normale anbefalinger går ut på at en tilfører noe mer enn minimumsnormen tilrår.»
// PDF (unghest): «Siden dette er en minimumsnorm, økes dette med 25 % under praktiske forhold.»
// Samme +25 %-prinsipp brukes konsekvent for voksne hester.
//
// KILDEPRIORITET: PDF «Fôring av hest» trumfer NRC der de er ulike.
// NRC brukes kun for Ca/P-tallverdier da PDF ikke oppgir disse eksplisitt.
// Energi og protein beregnes alltid fra PDF-formler.
// ============================================================
const ADULT_MINERALS = {
  // g Ca og P per 100 kg kroppsvekt/dag (NRC 2007 × 1.25)
  vedlikehold:   { ca: 5.00,  p: 3.50 },
  lett:          { ca: 7.50,  p: 4.53 },
  moderat:       { ca: 8.75,  p: 5.25 },
  hard:          { ca: 10.00, p: 7.25 },
  intens:        { ca: 11.25, p: 8.25 },
  drektig_9:     { ca: 7.75,  p: 5.50 },
  drektig_10:    { ca: 8.50,  p: 6.00 },
  drektig_11:    { ca: 9.00,  p: 6.50 },
};

// Laktasjon Ca/P: individuelle månedsverdier (NRC 2007 × 1.25, 500 kg referanse)
// Månedsvise verdier eliminerer grupperingsfeil ved månedsskift.
const LAKT_MINERALS = {
  1: { ca: 14.75, p: 9.50 },
  2: { ca: 14.25, p: 9.25 },
  3: { ca: 14.00, p: 9.00 },
  4: { ca: 12.00, p: 7.50 },
  5: { ca: 10.00, p: 6.25 },
  6: { ca:  9.00, p: 5.50 },
};

function adultMinerals(level, pregMonth, lactMonth) {
  // Laktasjon: individuelle månedsverdier (LAKT_MINERALS)
  if (lactMonth >= 1 && lactMonth <= 6) return LAKT_MINERALS[lactMonth];
  // Drektighet
  if (pregMonth >= 11) return ADULT_MINERALS.drektig_11;
  if (pregMonth >= 10) return ADULT_MINERALS.drektig_10;
  if (pregMonth >= 9)  return ADULT_MINERALS.drektig_9;
  // Trening / vedlikehold
  const keys = ["vedlikehold", "lett", "moderat", "hard", "intens"];
  return ADULT_MINERALS[keys[level] || "vedlikehold"];
}

