function calculateBCS(scores) {
  const vals = Object.values(scores);
  if (vals.length < 6) return null;
  const counts = [0, 0, 0, 0, 0, 0];
  vals.forEach(v => counts[v]++);
  let maxCount = 0, maxClass = 3;
  for (let i = 1; i <= 5; i++) {
    if (counts[i] > maxCount) { maxCount = counts[i]; maxClass = i; }
  }
  const tied = [];
  for (let i = 1; i <= 5; i++) { if (counts[i] === maxCount) tied.push(i); }
  if (tied.length > 1) {
    const sorted = [...vals].sort((a, b) => a - b);
    maxClass = sorted[2] <= sorted[3] ? sorted[2] : sorted[3];
    if (sorted[2] !== sorted[3]) maxClass = Math.round((sorted[2] + sorted[3]) / 2);
  }
  return maxClass;
}

// ============================================================
// Centralized FEh calculation — used by live bar + summary
// Two paths: young horse (PDF formulas) vs adult horse
// ============================================================
function computeFEh(data) {
  const w = data.weight || 0;
  if (w < 50) return null;

  const breed = BREEDS.find(b => b.name === data.breed);
  const isYoung = data.ageMonths !== null && data.ageMonths < 36;

  const level = data.trainingLevelOverride !== null
    ? data.trainingLevelOverride
    : calculateTrainingLevel(data.frequency, data.conditioning, data.duration);

  // BCS factor (not applied to young horses under 12 months)
  const applyBcs = !(isYoung && data.ageMonths < 12);
  const bcsFactor = (applyBcs && data.bcs) ? { 1: 1.2, 2: 1.1, 3: 1.0, 4: 0.9, 5: 0.8 }[data.bcs] : 1.0;

  if (isYoung) {
    // ═══ UNGHEST — PDF formulas ═══
    const age = data.ageMonths;
    const adultWeight = w; // w = voksenvekt for unghest
    const pct = growthPct(age);
    const currentWeight = adultWeight * pct / 100;
    const dtv = dailyGain(age, adultWeight) / 1000; // kg/day

    // Vedlikehold (egne koeffisienter, ingen rase/kjønn-korreksjon)
    const koeff = youngMaintenanceCoeff(age);
    const metW = Math.pow(currentWeight, 0.75);
    const fehVedlikehold = koeff * metW;

    // Vekstenergi: FEh = DTV × (1350 + 67.94×alder − 1.093×alder²) / 1000
    const fehVekst = dtv > 0
      ? dtv * (1350 + 67.94 * age - 1.093 * age * age) / 1000
      : 0;

    // Trening (lavere faktorer, maks nivå 3)
    const tFactors = [0, 0.20, 0.40, 0.60];
    const cappedLevel = Math.min(level, 3);
    const tF = tFactors[cappedLevel] || 0;

    // Oppdrettstillegg (PDF: +25 % intensiv, +10 % utegang i flokk)
    let rearingF = 0;
    if (data.youngIntensiveRearing) rearingF += 0.25;
    if (data.youngOutdoorHerd) rearingF += 0.10;

    const fehBeforeBcs = (fehVedlikehold + fehVekst) * (1 + tF + rearingF);
    const fehFinal = fehBeforeBcs * bcsFactor;

    // Protein
    const protRatio = youngProteinRatio(age);
    const proteinTotal = fehFinal * protRatio;

    // Lysin (PDF Tabell 8)
    const lysinRatio = youngLysinRatio(age);
    const lysinTotal = fehFinal * lysinRatio;

    // Mineraler (NRC + 25 %)
    const ca = (currentWeight * 0.072 + 32 * dtv) * 1.25;
    const p = (currentWeight * 0.040 + 17.8 * dtv) * 1.25;

    return {
      isYoung: true,
      currentWeight: Math.round(currentWeight),
      adultWeight,
      pctOfAdult: Math.round(pct),
      dtv: Math.round(dtv * 1000), // g/day for display
      koeff,
      fehVedlikehold,
      fehVekst,
      tF,
      rearingF,
      level: cappedLevel,
      bcsFactor,
      total: fehBeforeBcs,
      final: fehFinal,
      proteinRatio: protRatio,
      proteinTotal: Math.round(proteinTotal),
      lysinRatio,
      lysinTotal: Math.round(lysinTotal * 10) / 10,
      ca: Math.round(ca * 10) / 10,
      p: Math.round(p * 10) / 10,
      caPRatio: p > 0 ? Math.round((ca / p) * 10) / 10 : null,
      // Compatibility fields for display
      base: fehVedlikehold,
      breedingF: 0,
      lactFEh: 0,
    };
  }

  // ═══ VOKSEN — PDF formulas ═══
  const tf = breed ? CATEGORY_FACTORS[breed.category] : 1.0;
  const sf = data.sex === "hingst" ? 1.1 : 1.0;
  const metW = Math.pow(w, 0.75);
  const base = 0.0373 * metW * tf * sf;

  // Trening
  const trainingFactors = [0, 0.25, 0.50, 0.75, 1.00];
  const tF = trainingFactors[level] || 0;
  const fehTrening = base * tF;

  // Drektighet (prosent av vedlikehold)
  const pregFactors = { 0: 0, 9: 0.15, 10: 0.25, 11: 0.30 };
  const dF = pregFactors[data.pregMonth] || 0;
  const fehDrekt = base * dF;

  // Laktasjon (absolutt tillegg per 100 kg)
  let lactFEh = 0;
  const lm = data.lactMonth || 0;
  if (lm > 0) {
    const lactTable = w < 200 ? LACT_ENERGY_SMALL : LACT_ENERGY_LARGE;
    const perHundred = lactTable[lm] || 0;
    lactFEh = perHundred * w / 100;
  }

  const fehBeforeBcs = base + fehTrening + fehDrekt + lactFEh;
  const fehFinal = fehBeforeBcs * bcsFactor;

  // Protein — 80 g/FEh for vedlikehold + trening (PDF s. 208)
  // Drektighetsenergi gir IKKE ekstra protein — Tabell 10 dekker dette via absolutt tillegg.
  let proteinBase = (base + fehTrening) * 80;
  // Drektighet protein — absolutt tillegg (PDF Tabell 10)
  let proteinDrekt = 0;
  if (data.pregMonth >= 8) {
    proteinDrekt = (PREG_PROTEIN_PER_100KG[data.pregMonth] || 0) * w / 100;
  }
  // Laktasjon protein — basert på melkemengde (PDF Tabell 11 + 13)
  let proteinLakt = 0;
  if (lm > 0) {
    const milkTable = w < 200 ? LACT_MILK_SMALL : LACT_MILK_LARGE;
    const milkKgDay = (milkTable[lm] || 0) * w / 100;
    proteinLakt = milkKgDay * (LACT_PROT_PER_KG_MILK[lm] || 0);
  }
  const proteinTotal = proteinBase + proteinDrekt + proteinLakt;

  // Lysin — voksne: 4 g/FEh (PDF)
  const lysinTotal = fehFinal * 4;

  // Mineraler voksen (SPEC v2.2 seksjon 4, lineær modell)
  const minerals = adultMinerals(level, data.pregMonth, lm);
  const ca = minerals.ca * w / 100;
  const p = minerals.p * w / 100;

  return {
    isYoung: false,
    base,
    tF,
    dF,
    fehTrening,
    fehDrekt,
    lactFEh,
    breedingF: dF,
    bcsFactor,
    total: fehBeforeBcs,
    final: fehFinal,
    level,
    proteinTotal: Math.round(proteinTotal),
    proteinBase: Math.round(proteinBase),
    proteinDrekt: Math.round(proteinDrekt),
    proteinLakt: Math.round(proteinLakt),
    lysinTotal: Math.round(lysinTotal * 10) / 10,
    ca: Math.round(ca * 10) / 10,
    p: Math.round(p * 10) / 10,
    caPRatio: p > 0 ? Math.round((ca / p) * 10) / 10 : null,
  };
}

